module sr_latch (  
    input Anti_S,  
    input R,  
    output reg Q,  
    output Qn  
);  
    assign Qn = ~Q;  
    always @ (Anti_S or R) begin  
        if (Anti_S && ~R)  
            Q <= 1;  
        else if (~Anti_S && R)  
            Q <= 0;  
        // If both are 0, maintain the previous state  
    end  
endmodule
